export const runScenario = (input: {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}): { results: Result[] } => {
  const results = input.steps.map((step) => {
    const base = step.items.reduce((sum, item) => {
      if (item.type === "sword") return sum + SWORD_BASE;
      return sum;
    }, 0);
